package com.holoscript.generated

import android.os.Bundle
import android.view.MotionEvent
import android.view.View
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.ViewModelProvider
import com.google.ar.core.*
import com.google.ar.core.exceptions.*
import com.google.ar.sceneform.*
import com.google.ar.sceneform.math.Vector3
import com.google.ar.sceneform.rendering.*
import com.google.ar.sceneform.ux.*
import java.util.concurrent.CompletableFuture

class GeneratedARSceneActivity : AppCompatActivity() {
    private lateinit var arFragment: ArFragment
    private lateinit var sceneState: SceneState
    private val placedNodes = mutableMapOf<String, TransformableNode>()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_ar_scene)

        sceneState = ViewModelProvider(this)[SceneState::class.java]
        arFragment = supportFragmentManager.findFragmentById(R.id.ar_fragment) as ArFragment

        setupARSession()
        setupTapListener()
        setupUI()
    }

    private fun setupARSession() {
        arFragment.arSceneView.scene.addOnUpdateListener { frameTime ->
            val frame = arFragment.arSceneView.arFrame ?: return@addOnUpdateListener

            // Track planes
            for (plane in frame.getUpdatedTrackables(Plane::class.java)) {
                if (plane.trackingState == TrackingState.TRACKING) {
                    sceneState.onPlaneDetected(plane)
                }
            }
        }
    }

    private fun setupTapListener() {
        arFragment.setOnTapArPlaneListener { hitResult, plane, motionEvent ->
            if (plane.type != Plane.Type.HORIZONTAL_UPWARD_FACING) return@setOnTapArPlaneListener

            placeObject(hitResult)
        }
    }

    private fun placeObject(hitResult: HitResult) {
        val anchor = hitResult.createAnchor()
        val anchorNode = AnchorNode(anchor)
        anchorNode.setParent(arFragment.arSceneView.scene)

        // Create node from factory
        NodeFactory.createDefaultNode(this) { renderable ->
            val transformableNode = TransformableNode(arFragment.transformationSystem)
            transformableNode.setParent(anchorNode)
            transformableNode.renderable = renderable
            transformableNode.select()

            val id = java.util.UUID.randomUUID().toString()
            placedNodes[id] = transformableNode

            // Setup interaction
            transformableNode.setOnTapListener { _, _ ->
                sceneState.onNodeTapped(id)
                animateNodeTap(transformableNode)
            }

            android.util.Log.d("HoloScript", "Placed object: $id")
        }
    }

    private fun animateNodeTap(node: TransformableNode) {
        val originalScale = node.localScale
        val scaledUp = Vector3(originalScale.x * 1.2f, originalScale.y * 1.2f, originalScale.z * 1.2f)

        android.animation.ObjectAnimator.ofObject(
            node, "localScale",
            com.google.ar.sceneform.math.Vector3Evaluator(),
            originalScale, scaledUp, originalScale
        ).apply {
            duration = 200
            start()
        }
    }

    private fun setupUI() {
        findViewById<View>(R.id.reset_button)?.setOnClickListener {
            resetScene()
        }
    }

    private fun resetScene() {
        for (node in placedNodes.values) {
            node.anchor?.detach()
            node.setParent(null)
        }
        placedNodes.clear()

        sceneState.reset()
        Toast.makeText(this, "Scene reset", Toast.LENGTH_SHORT).show()
    }

    override fun onResume() {
